// Mevcut yılı al
const year = new Date().getFullYear();

// Hicri yıl hesapla (yaklaşık formül + fallback loop)
const hijriYear = Math.floor((year - 622) / 0.97);

// --- 1. Milli tatiller: date.nager.at ---
let nationalHolidays = [];
try {
  const res = await fetch(`https://date.nager.at/api/v3/PublicHolidays/${year}/TR`);
  nationalHolidays = await res.json();
  console.log('Nager.at:', nationalHolidays.length, 'tatil bulundu');
} catch(e) {
  console.log('Nager.at hatası:', e.message);
}

// --- 2. Ramazan Bayramı: 1 Şevval ---
let eidFitrDate = null;
for (const hy of [hijriYear, hijriYear + 1]) {
  try {
    const res = await fetch(`https://api.aladhan.com/v1/hToG/01-10-${hy}`);
    const data = await res.json();
    const parts = data.data.gregorian.date.split('-'); // DD-MM-YYYY
    const dateStr = `${parts[2]}-${parts[1]}-${parts[0]}`; // YYYY-MM-DD
    console.log(`Ramazan Bayramı hicri ${hy}:`, dateStr);
    if (dateStr.startsWith(String(year))) {
      eidFitrDate = dateStr;
      break;
    }
  } catch(e) {
    console.log('Aladhan Ramazan hatası:', e.message);
  }
}

// --- 3. Kurban Bayramı: 10 Zilhicce ---
let eidAdhaDate = null;
for (const hy of [hijriYear, hijriYear + 1]) {
  try {
    const res = await fetch(`https://api.aladhan.com/v1/hToG/10-12-${hy}`);
    const data = await res.json();
    const parts = data.data.gregorian.date.split('-'); // DD-MM-YYYY
    const dateStr = `${parts[2]}-${parts[1]}-${parts[0]}`; // YYYY-MM-DD
    console.log(`Kurban Bayramı hicri ${hy}:`, dateStr);
    if (dateStr.startsWith(String(year))) {
      eidAdhaDate = dateStr;
      break;
    }
  } catch(e) {
    console.log('Aladhan Kurban hatası:', e.message);
  }
}

// --- Türkçe isim eşleştirme ---
const nameMap = {
  "New Year's Day": 'Yılbaşı',
  "National Independence & Children's Day": 'Ulusal Egemenlik ve Çocuk Bayramı',
  'Labour Day': 'İşçi Bayramı',
  "Atatürk Commemoration & Youth Day": "Atatürk'ü Anma, Gençlik ve Spor Bayramı",
  'Democracy and National Unity Day': 'Demokrasi ve Millî Birlik Günü',
  'Victory Day': 'Zafer Bayramı',
  'Republic Day': 'Cumhuriyet Bayramı',
};

// --- Tatil listesini oluştur ---
const holidays = [];

// 1. Milli tatiller (nager.at)
for (const h of nationalHolidays) {
  holidays.push({
    year,
    date: h.date,
    name_tr: nameMap[h.name] || h.name,
    name_en: h.name,
    category: 'national'
  });
}

// 2. 18 Mart Çanakkale (nager.at'ta yok)
holidays.push({
  year,
  date: `${year}-03-18`,
  name_tr: 'Çanakkale Şehitlerini Anma Günü',
  name_en: 'Canakkale Martyrs Commemoration Day',
  category: 'national'
});

// 3. Ramazan Bayramı (dini)
if (eidFitrDate) {
  const eidDate = new Date(eidFitrDate);
  const arife = new Date(eidDate);
  arife.setDate(arife.getDate() - 1);
  if (arife.getFullYear() === year) {
    holidays.push({ year, date: arife.toISOString().split('T')[0], name_tr: 'Ramazan Bayramı Arife', name_en: 'Eid al-Fitr Eve', category: 'religious' });
  }
  for (let i = 0; i < 3; i++) {
    const d = new Date(eidDate);
    d.setDate(d.getDate() + i);
    if (d.getFullYear() === year) {
      holidays.push({ year, date: d.toISOString().split('T')[0], name_tr: `Ramazan Bayramı ${i+1}. Gün`, name_en: `Eid al-Fitr Day ${i+1}`, category: 'religious' });
    }
  }
} else {
  console.log('UYARI: Ramazan Bayramı tarihi bulunamadı!');
}

// 4. Kurban Bayramı (dini)
if (eidAdhaDate) {
  const eidDate = new Date(eidAdhaDate);
  const arife = new Date(eidDate);
  arife.setDate(arife.getDate() - 1);
  if (arife.getFullYear() === year) {
    holidays.push({ year, date: arife.toISOString().split('T')[0], name_tr: 'Kurban Bayramı Arife', name_en: 'Eid al-Adha Eve', category: 'religious' });
  }
  for (let i = 0; i < 4; i++) {
    const d = new Date(eidDate);
    d.setDate(d.getDate() + i);
    if (d.getFullYear() === year) {
      holidays.push({ year, date: d.toISOString().split('T')[0], name_tr: `Kurban Bayramı ${i+1}. Gün`, name_en: `Eid al-Adha Day ${i+1}`, category: 'religious' });
    }
  }
} else {
  console.log('UYARI: Kurban Bayramı tarihi bulunamadı!');
}

// 5. Ticari günler
function getNthWeekday(yr, month, weekday, n) {
  const d = new Date(yr, month, 1);
  const firstDay = d.getDay();
  let offset = weekday - firstDay;
  if (offset < 0) offset += 7;
  const firstDate = 1 + offset;
  const targetDate = firstDate + (n - 1) * 7;
  return new Date(yr, month, targetDate).toISOString().split('T')[0];
}

holidays.push({ year, date: `${year}-02-14`, name_tr: 'Sevgililer Günü', name_en: "Valentine's Day", category: 'commercial' });
holidays.push({ year, date: getNthWeekday(year, 4, 0, 2), name_tr: 'Anneler Günü', name_en: "Mother's Day", category: 'commercial' });
holidays.push({ year, date: getNthWeekday(year, 5, 0, 3), name_tr: 'Babalar Günü', name_en: "Father's Day", category: 'commercial' });
holidays.push({ year, date: getNthWeekday(year, 10, 5, 4), name_tr: 'Black Friday', name_en: 'Black Friday', category: 'commercial' });

console.log('Toplam tatil sayısı:', holidays.length);
return holidays.map(h => ({ json: h }));

const items = $input.all();
if (items.length === 0) {
  return [{ json: { sql: 'SELECT 1', count: 0, year: new Date().getFullYear() } }];
}

const escape = (s) => String(s || '').replace(/'/g, "''");

const values = items.map(item => {
  const h = item.json;
  return `(${h.year}, '${h.date}'::date, '${escape(h.name_tr)}', '${escape(h.name_en)}', '${escape(h.category)}')`;
}).join(',\n');

const sql = `INSERT INTO social.public_holidays (year, date, name_tr, name_en, category)\nVALUES ${values}\nON CONFLICT (year, date) DO UPDATE SET\n  name_tr = EXCLUDED.name_tr,\n  name_en = EXCLUDED.name_en,\n  category = EXCLUDED.category`;

const year = items[0].json.year;
return [{ json: { sql, count: items.length, year } }];

